import{_ as t,C as r,o,c as l,E as s,ai as i}from"./chunks/framework.D76zamVX.js";const f=JSON.parse('{"title":"Хто я такий","description":"","frontmatter":{},"headers":[],"relativePath":"pages/me.md","filePath":"pages/me.md","lastUpdated":1750870677000}'),n={name:"pages/me.md"};function h(d,e,p,c,m,u){const a=r("Banner");return o(),l("div",null,[s(a,{text:"Про мене",image:"/pages/me.jpg",blur:"5px"}),e[0]||(e[0]=i('<h1 id="хто-я-такии" tabindex="-1">Хто я такий <a class="header-anchor" href="#хто-я-такии" aria-label="Permalink to &quot;Хто я такий&quot;">​</a></h1><p>Я звичайна людина з України, котра почала українізацію себе після 22-го року, на жаль, що тільки з того часу.</p><p>Почав займатися лінуксами ще коли був студентом, поставив Armbian на свій твбокс й був здивований, що тут є зручна консоль та управління застосунками.</p><p>Десь у 20 році подарували офісний ПК як сервер й мої таргани у голові почали рух, котрий є досі, кхе</p><h2 id="навічки" tabindex="-1">Навічки <a class="header-anchor" href="#навічки" aria-label="Permalink to &quot;Навічки&quot;">​</a></h2><h3 id="selfhost-linux" tabindex="-1">SelfHost / Linux <a class="header-anchor" href="#selfhost-linux" aria-label="Permalink to &quot;SelfHost / Linux&quot;">​</a></h3><p>Як написав зверху, почав селфхостити десь у 20 році, спочатку це був Jellyfin, медіасервер. Потім звернув увагу на Home Assistant, але у той час нічого з розумного не було (я теж).</p><p><img src="https://shkey.cakestwix.com/files/20013462-65b5-44dc-882e-8da3e5687814.webp" alt="Selfhost схема моєї системи"></p><p>Моя поточна схема селфхостінгу, але не дуже поточна, зараз трохи поміняв у Jellyfin, але це не дуже важливо зараз</p><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><p>Займатися кастомами почав після того, як не випадково видалив Google Play Service на своєму телефоні, десь пів року не міг відновити це, але розібрався та відразу прошився на кастом й був здивований, наскільки система інша</p><p>Пішов на завод, попрацював місяць, купив новий телефон - LeEco Le 2. Це були перші враження від нового андроїду й перший досвід зі збіркою Android.</p><p>Зараз збираю під Lenovo Z5s, телефон десь 2019 року, котрий має оф тільки А9, але завдяки мені та друзям, він має сучасний А15 й у планах А16</p><h2 id="проекти" tabindex="-1">Проекти <a class="header-anchor" href="#проекти" aria-label="Permalink to &quot;Проекти&quot;">​</a></h2><h3 id="cloudstream3" tabindex="-1">Cloudstream3 <a class="header-anchor" href="#cloudstream3" aria-label="Permalink to &quot;Cloudstream3&quot;">​</a></h3><p>Самий популярний проект у мене - <a href="https://github.com/CakesTwix/cloudstream-extensions-uk" target="_blank" rel="noreferrer">піратські парсери під CS3</a>, щоб дивитися медіа-контент з застосунку. Це була спроба уйти від Jellyfin, але він не дуже вдалий, але якщо подивитися на популярність - доволі круто, що він існує</p><h3 id="toloka2web-stack" tabindex="-1">Toloka2Web Stack <a class="header-anchor" href="#toloka2web-stack" aria-label="Permalink to &quot;Toloka2Web Stack&quot;">​</a></h3><p>Почалось як звичайний скріпт на пітоні, щоб робити нормальний неймінг через торрент клієнт тому що ваши мальчики не можуть у нього й не хочуть. Підключився одна людина до цієї проекту та він переріс у <a href="https://github.com/CakesTwix/Toloka2MediaServer" target="_blank" rel="noreferrer">великий скіпт</a> та навіть <a href="https://codeberg.org/CakesTwix/Toloka2WebV2" target="_blank" rel="noreferrer">веб-застосунком</a></p><h3 id="цеи-саит" tabindex="-1">Цей сайт 😃 <a class="header-anchor" href="#цеи-саит" aria-label="Permalink to &quot;Цей сайт :)&quot;">​</a></h3><p>Усе почалося після того, як побачив <a href="https://wotaku.wiki/" target="_blank" rel="noreferrer">https://wotaku.wiki/</a>. Захотілося щось подібне, але під українців, але як бачите, роблю вже більше під себе</p>',20))])}const b=t(n,[["render",h]]);export{f as __pageData,b as default};
